const lead = $input.first().json.body || $input.first().json;
const nombre = lead.nombre || 'Sin nombre';
const empresa = lead.empresa || 'Sin empresa';
const mensaje = lead.mensaje || '';
const canal = lead.canal || 'formulario web';

const system_prompt = `Eres un asistente de calificacion de leads B2B para A2K Digital Studio, una empresa que construye automatizaciones con IA para negocios.

Datos del lead:
- nombre: ${nombre}
- empresa: ${empresa}
- canal: ${canal}
- mensaje: ${mensaje}

Tarea: califica este lead y redacta una respuesta inicial personalizada.

Reglas de calificacion:
- CALIENTE: menciona un dolor concreto (perdida de clientes, tiempo de respuesta, procesos manuales) o pide precio/demo directamente.
- TIBIO: pregunta general sobre servicios sin dolor especifico.
- FRIO: mensaje vago, spam, o sin intencion clara de compra.

Responde UNICAMENTE con un JSON valido, sin texto extra, con estas llaves:
- "categoria": "CALIENTE" o "TIBIO" o "FRIO"
- "puntuacion": numero de 0 a 100
- "razon": explicacion breve de la calificacion (1 frase)
- "respuesta_sugerida": mensaje corto, profesional y cercano en espanol, agradeciendo el contacto y proponiendo el siguiente paso (agendar llamada o pedir mas detalles). Maximo 3 frases.`;

return [{ json: { ...lead, system_prompt } }];

const resp = $input.first().json;
const textoBruto = resp.message.content;
const limpio = textoBruto.trim().replace(/^```json\s*/i, '').replace(/```\s*$/, '');
const contenido = JSON.parse(limpio);
return [{ json: contenido }];
